#include <iostream>
#include <vector>

using namespace std;

vector<int> intersect(vector<int> &nums1, vector<int> &nums2)
{
    vector<bool> used(nums1.size(), false);
    vector<int> result;

    for (int b : nums2)
    {
        for (int i = 0; i < nums1.size(); i++)
        {
            if (!used[i] && nums1[i] == b)
            {
                result.push_back(b);
                used[i] = true;
                break;
            }
        }
    }

    return result;
}

int main()
{
    vector<int> nums1 = {1, 2, 2, 1};
    vector<int> nums2 = {2, 2};

    vector<int> result = intersect(nums1, nums2);
    for (int r : result) cout << r << " ";

    return 0;
}

#include <iostream>
#include <vector>
#include <unordered_map>

using namespace std;

vector<int> intersect(vector<int> &nums1, vector<int> &nums2)
{
    unordered_map<int, int> counts;
    for (int a : nums1) counts[a]++;

    vector<int> result;
    for (int b : nums2)
    {
        if (counts[b] > 0)
        {
            result.push_back(b);
            counts[b]--;
        }
    }

    return result;
}

int main()
{
    vector<int> nums1 = {1, 2, 2, 1};
    vector<int> nums2 = {2, 2};

    vector<int> result = intersect(nums1, nums2);
    for (int r : result) cout << r << " ";

    return 0;
}

